#!/usr/bin/env bash
# add-bridge.sh — adds LCAI <-> Ethereum bridge tab (Hyperlane warp route UI)
# Run from the repo root (~/aether/app or wherever rokhill/filament lives).
set -euo pipefail
[ -f config/wagmi.ts ] || { echo "Run from the filament repo root"; exit 1; }

mkdir -p components/bridge app/bridge

base64 -d > config/bridge.ts <<'B64EOF'

B64EOF

base64 -d > contracts/warpRouteAbi.ts <<'B64EOF'

B64EOF

base64 -d > components/bridge/bridge-form.tsx <<'B64EOF'

B64EOF

base64 -d > app/bridge/page.tsx <<'B64EOF'

B64EOF

python3 - <<'EOF'
# Exact-match patches with assertion guards
p='components/swap-pools-tabs.tsx'; s=open(p).read()
old='''import { cn } from "@/lib/utils";

const tabs = [
  { href: "/", label: "Swap" },
  { href: "/pools", label: "Pools" },
];'''
new='''import { cn } from "@/lib/utils";
import { BRIDGE_ENABLED } from "@/config/bridge";

const tabs = [
  { href: "/", label: "Swap" },
  { href: "/pools", label: "Pools" },
  ...(BRIDGE_ENABLED ? [{ href: "/bridge", label: "Bridge" }] : []),
];'''
assert old in s, "swap-pools-tabs anchor not found"
open(p,'w').write(s.replace(old,new))

p='config/wagmi.ts'; s=open(p).read()
old='import config from ".";'
new='import config from ".";\nimport { BRIDGE_ENABLED, ethereum } from "./bridge";'
assert old in s, "wagmi import anchor not found"
s=s.replace(old,new)
old='export const networks = config.chains;'
new='''export const networks = (
  BRIDGE_ENABLED ? [...config.chains, ethereum] : config.chains
) as typeof config.chains;'''
assert old in s, "wagmi networks anchor not found"
s=s.replace(old,new)
open(p,'w').write(s)

p='.env.example'; s=open(p).read()
if 'NEXT_PUBLIC_BRIDGE_ENABLED' not in s:
    s+='''
# Bridge (LCAI <-> Ethereum via LightChain's Hyperlane warp route)
# Set to "false" to hide the Bridge tab entirely.
NEXT_PUBLIC_BRIDGE_ENABLED=true
# Optional dedicated Ethereum RPC (Alchemy/Infura). Defaults to a public RPC.
NEXT_PUBLIC_ETH_RPC_URL=
'''
    open(p,'w').write(s)
print("patches applied")
EOF

npx tsc --noEmit && echo "BRIDGE ADDED — typecheck clean"
